function cS(trades){
  const z={total:0,wins:0,losses:0,bes:0,winRate:0,totalR:0,totalDollar:0,bestR:0,worstR:-1,profitFactor:0,expectancy:0,expectDollar:0,avgDDpct:0,avgDurWin:0,avgDurSL:0,avgDurBE:0,maxWinStreak:0,maxLossStreak:0,curWinStreak:0,curLossStreak:0,recoveryFactor:0,sharpeRatio:0,payoffRatio:0,sampleValid:false,maxEquityDD:0}
  if(!trades.length)return z
  const rs=trades.map(gR),w=rs.filter(r=>r>0),l=rs.filter(r=>r<0),b=rs.filter(r=>r===0)
  const tR=Math.round(rs.reduce((a,c)=>a+c,0)*100)/100,gw=w.reduce((a,r)=>a+r,0),gl=Math.abs(l.reduce((a,r)=>a+r,0))
  const dd=trades.map(gDD).filter(v=>v!==null),aDD=dd.length?Math.round(dd.reduce((a,c)=>a+c,0)/dd.length*100)/100:0
  const exp=Math.round((tR/trades.length)*100)/100
  const durW=trades.filter(t=>t.resultado==="WIN").map(t=>pn(t.duracionTrade)).filter(v=>v>0)
  const durS=trades.filter(t=>t.resultado==="SL").map(t=>pn(t.duracionTrade)).filter(v=>v>0)
  const durB=trades.filter(t=>t.resultado==="BE").map(t=>pn(t.duracionTrade)).filter(v=>v>0)
  let mxW=0,mxL=0,cW=0,cL=0
  const sorted=[...trades].sort((a,b2)=>new Date(a.fecha)-new Date(b2.fecha))
  sorted.forEach(t=>{const r=gR(t);if(r>0){cW++;cL=0}else if(r<0){cL++;cW=0}else{cW=0;cL=0};mxW=Math.max(mxW,cW);mxL=Math.max(mxL,cL)})
  let peak=0,maxDD2=0,cum=0
  sorted.forEach(t=>{cum+=gR(t);if(cum>peak)peak=cum;const d2=peak-cum;if(d2>maxDD2)maxDD2=d2})
  const recovF=maxDD2>0?Math.round(tR/maxDD2*100)/100:tR>0?Infinity:0
  const mean=tR/trades.length,variance=rs.reduce((a,r)=>a+Math.pow(r-mean,2),0)/rs.length
  const sharpe=Math.sqrt(variance)>0?Math.round(mean/Math.sqrt(variance)*100)/100:0
  const avgWR=w.length?gw/w.length:0,avgLR=l.length?gl/l.length:1
  const payoff=avgLR>0?Math.round(avgWR/avgLR*100)/100:avgWR>0?Infinity:0
  return{total:trades.length,wins:w.length,losses:l.length,bes:b.length,winRate:Math.round(w.length/trades.length*10000)/100,totalR:tR,totalDollar:Math.round(tR*RV),bestR:rs.length?Math.max(...rs):0,worstR:rs.length?Math.min(...rs):0,profitFactor:gl?Math.round(gw/gl*10000)/10000:gw>0?Infinity:0,expectancy:exp,expectDollar:Math.round(exp*RV),avgDDpct:aDD,avgDurWin:durW.length?Math.round(durW.reduce((a,c)=>a+c,0)/durW.length):0,avgDurSL:durS.length?Math.round(durS.reduce((a,c)=>a+c,0)/durS.length):0,avgDurBE:durB.length?Math.round(durB.reduce((a,c)=>a+c,0)/durB.length):0,maxWinStreak:mxW,maxLossStreak:mxL,curWinStreak:cW,curLossStreak:cL,recoveryFactor:recovF,sharpeRatio:sharpe,payoffRatio:payoff,sampleValid:trades.length>=30,maxEquityDD:Math.round(maxDD2*100)/100}
}
const grpBy=(trades,fn)=>{const m={};trades.forEach(t=>{const k=fn(t);if(k)(m[k]??=[]).push(t)});return Object.entries(m).sort((a,b)=>b[0].localeCompare(a[0])).map(([k,ts])=>({key:k,...cS(ts)}))}
function extraS(trades){if(!trades.length)return{bestDay:"-",worstDay:"-",avgOps:0,bestWd:"-",worstWd:"-"};const bd={};trades.forEach(t=>{if(t.fecha)(bd[t.fecha]??=[]).push(t)});const dt=Object.entries(bd).map(([d,ts])=>({d,r:ts.reduce((a,t)=>a+gR(t),0)}));const b=dt.reduce((a,x)=>x.r>a.r?x:a,dt[0]),ww=dt.reduce((a,x)=>x.r<a.r?x:a,dt[0]);const bw2={};trades.forEach(t=>{if(!t.fecha)return;(bw2[getDN(t.fecha)]??=[]).push(t)});const wt=Object.entries(bw2).map(([wd,ts])=>({wd,r:ts.reduce((a,t)=>a+gR(t),0)}));const bw=wt.reduce((a,x)=>x.r>a.r?x:a,wt[0]),wwk=wt.reduce((a,x)=>x.r<a.r?x:a,wt[0]);return{bestDay:`${fmtD(b.d)} (${b.r>0?"+":""}${Math.round(b.r*100)/100}R)`,worstDay:`${fmtD(ww.d)} (${ww.r>0?"+":""}${Math.round(ww.r*100)/100}R)`,avgOps:Math.round(trades.length/Object.keys(bd).length*100)/100,bestWd:`${bw.wd} (${bw.r>0?"+":""}${Math.round(bw.r*100)/100}R)`,worstWd:`${wwk.wd} (${wwk.r>0?"+":""}${Math.round(wwk.r*100)/100}R)`}}
function rDist(trades,field){const vs=trades.filter(t=>t.resultado==="WIN").map(t=>Math.round(pn(t[field]))).filter(v=>v>0);if(!vs.length)return{lvl:[],cnt:[],pct:[]};const mx=Math.max(...vs),lvl=[],cnt=[],pct=[];for(let r=1;r<=Math.min(mx,15);r++){const c=vs.filter(v=>v===r).length;lvl.push(r+"R");cnt.push(c);pct.push(Math.round(c/vs.length*10000)/100)}if(vs.some(v=>v>15)){const c=vs.filter(v=>v>15).length;lvl.push("16R+");cnt.push(c);pct.push(Math.round(c/vs.length*10000)/100)}return{lvl,cnt,pct}}
function hourAn(trades){const bh={};trades.forEach(t=>{const b=hBucket(t.horaInicio);if(b)(bh[b]??=[]).push(t)});return Object.entries(bh).sort((a,b)=>a[0].localeCompare(b[0])).map(([h,ts])=>{const s=cS(ts),rm=ts.filter(t=>t.resultado==="WIN").map(t=>pn(t.rMaximo)).filter(v=>v>0);return{hour:h,...s,avgRmax:rm.length?Math.round(rm.reduce((a,c)=>a+c,0)/rm.length*100)/100:0}})}
function atrAn(trades){return[[0,10,"0-10"],[10,15,"10-15"],[15,20,"15-20"],[20,25,"20-25"],[25,30,"25-30"],[30,40,"30-40"],[40,999,"40+"]].map(([lo,hi,l])=>({range:l,...cS(trades.filter(t=>{const a=pn(t.atr);return a>lo&&a<=hi}))})).filter(x=>x.total>0)}
function slAn(trades){return[[0,15,"1-15"],[15,20,"15-20"],[20,25,"20-25"],[25,30,"25-30"],[30,40,"30-40"],[40,999,"40+"]].map(([lo,hi,l])=>({range:l,...cS(trades.filter(t=>{const p=pn(t.puntosSlStr);return p>lo&&p<=hi}))})).filter(x=>x.total>0)}
function tips(trades){if(trades.length<5)return[];const t=[],s=cS(trades),ha=hourAn(trades),aa=atrAn(trades),sa=slAn(trades);if(ha.length){const best=ha.reduce((a,x)=>x.totalR>a.totalR?x:a,ha[0]);if(best.total>=3)t.push({type:"green",text:`Mejor hora: ${best.hour} ${best.winRate.toFixed(2)}%WR ${best.totalR>0?"+":""}${best.totalR}R`})}if(ha.length){const worst=ha.reduce((a,x)=>x.totalR<a.totalR?x:a,ha[0]);if(worst.total>=3&&worst.totalR<0)t.push({type:"red",text:`Evita ${worst.hour}: ${worst.totalR}R`})}if(aa.length>1){const best=aa.reduce((a,x)=>x.winRate>a.winRate&&x.total>=3?x:a,aa[0]);t.push({type:"green",text:`ATR ${best.range}: ${best.winRate.toFixed(2)}%WR`})}if(sa.length>1){const best=sa.reduce((a,x)=>x.winRate>a.winRate&&x.total>=3?x:a,sa[0]);t.push({type:"green",text:`SL ${best.range}pts: ${best.winRate.toFixed(2)}%WR`})}const wt2=trades.filter(t2=>t2.resultado==="WIN"&&pn(t2.rMaximo)>0&&pn(t2.rResultado)>0);if(wt2.length>=3){const at2=Math.round(wt2.reduce((a,t2)=>a+pn(t2.rResultado),0)/wt2.length*100)/100;const am=Math.round(wt2.reduce((a,t2)=>a+pn(t2.rMaximo),0)/wt2.length*100)/100;t.push({type:Math.round(at2/am*100)<50?"yellow":"green",text:`Capturas ${at2}R de ${am}R (${Math.round(at2/am*100)}%)`})}if(s.avgDurWin)t.push({type:"blue",text:`Dur: WIN=${s.avgDurWin}m SL=${s.avgDurSL}m`});if(s.maxLossStreak>=3)t.push({type:"red",text:`Racha loss max: ${s.maxLossStreak}${s.curLossStreak>=2?" (AHORA:"+s.curLossStreak+")":""}`});if(s.recoveryFactor!==Infinity&&s.recoveryFactor>0)t.push({type:s.recoveryFactor>=2?"green":"yellow",text:`Recovery: ${s.recoveryFactor.toFixed(2)}`});if(!s.sampleValid)t.push({type:"yellow",text:`${s.total}/30 trades min para stats confiables`});return t}

// NT8 CSV Parser
function parseNT8(csvText){
  const lines=csvText.split("\n").filter(l=>l.trim());if(lines.length<2)return[]
  const hd=lines[0].split(",").map(h=>h.trim())
  const rows=lines.slice(1).map(l=>{const vs=l.split(",").map(v=>v.trim());const o={};hd.forEach((h,i)=>o[h]=vs[i]||"");return o})
  // Group by Entry/Exit pairs using Order ID proximity and time
  const entries=rows.filter(r=>r["E/X"]==="Entry")
  const exits=rows.filter(r=>r["E/X"]==="Exit")
  const trades=[]
  entries.forEach(entry=>{
    const eTime=new Date(entry.Time)
    // Find exits within 30 min of entry
    const myExits=exits.filter(ex=>{const t2=new Date(ex.Time);return Math.abs(t2-eTime)<30*60*1000&&ex.Instrument===entry.Instrument})
    if(!myExits.length)return
    // Calc P&L
    const entryPrice=parseFloat(entry.Price)
    const isBuy=entry.Action==="Buy"
    let totalPnL=0
    myExits.forEach(ex=>{
      const exitPrice=parseFloat(ex.Price)
      const qty=parseInt(ex.Quantity)||1
      const pnl=isBuy?(exitPrice-entryPrice)*qty:(entryPrice-exitPrice)*qty
      totalPnL+=pnl
    })
    const totalQty=myExits.reduce((a,ex)=>a+(parseInt(ex.Quantity)||1),0)
    const lastExit=myExits[myExits.length-1]
    const exitTime=new Date(lastExit.Time)
    const fecha=`${eTime.getFullYear()}-${String(eTime.getMonth()+1).padStart(2,"0")}-${String(eTime.getDate()).padStart(2,"0")}`
    const hI=`${String(eTime.getHours()).padStart(2,"0")}:${String(eTime.getMinutes()).padStart(2,"0")}`
    const hF=`${String(exitTime.getHours()).padStart(2,"0")}:${String(exitTime.getMinutes()).padStart(2,"0")}`
    const durMin=Math.round((exitTime-eTime)/60000)
    // MNQ point value = $0.50 per point per contract... but we use R system
    // For now store raw P&L in points and let user assign R
    const pointsPnL=Math.round(totalPnL*100)/100/totalQty
    const resultado=totalPnL>0?"WIN":totalPnL<0?"SL":"BE"
    const account=entry.Account||""
    // Remove exits used
    myExits.forEach(ex=>{const idx=exits.indexOf(ex);if(idx>=0)exits.splice(idx,1)})
    trades.push({...DT,fecha,horaInicio:hI,horaFinal:hF,duracionTrade:String(durMin),buySell:isBuy?"BUY":"SELL",puntosSlStr:String(Math.abs(Math.round(pointsPnL*4)/4)),resultado,rResultado:resultado==="SL"?"-1":resultado==="BE"?"0":"1",notas:`NT8: ${entry.Instrument} x${totalQty} P&L=${totalPnL>0?"+":""}${Math.round(totalPnL*100)/100}pts`,account,parentAccount:entry.Connection||""})
  })
  return trades
}

